    const r=await db.query(`insert into work_requests (client_id,property_id,service_category_id,title,status,priority,description,internal_notes,assigned_user_id) values ($1,$2,$3,$4,$5,$6,$7,$8,$9) returning id::text`,[clientId,propertyId,serviceCategoryId,str(body.title)||'Service request',str(body.status,'new'),str(body.priority,'normal'),str(body.description),str(body.internalNotes),maybeUuid(body.assignedUserId)]);
