  if(match?.action==='create-deposit-invoice'&&method==='POST'){requireManage(user,'invoices'); const q=await db.query<any>(`select client_id::text as "clientId",total_cents,deposit_cents from quotes where id=$1`,[match.id]); if(!q.rows[0]) throw new HttpError(404,'Quote not found'); const total=Number(q.rows[0].deposit_cents||0)||Math.round(Number(q.rows[0].total_cents||0)*0.25); const inv=await db.query(`insert into invoices (client_id,quote_id,status,subtotal_cents,total_cents,balance_cents) values ($1,$2,'draft',$3,$3,$3) returning id::text`,[q.rows[0].clientId,match.id,total]); return{ok:true,id:inv.rows[0].id};}
