  const match=idParam(path,'jobs');const limit=readLimit(query);const scope=scopeClause(user,'j');
  if(!match&&method==='GET'){const r=await db.query(`select j.id::text,j.title,j.status,j.scope,j.assigned_user_id::text as "assignedUserId",u.name as technician,c.display_name as client,p.address as property,j.created_at::text as "createdAt",j.started_at::text as "startedAt",j.completed_at::text as "completedAt" from jobs j left join users u on u.id=j.assigned_user_id left join clients c on c.id=j.client_id left join properties p on p.id=j.property_id where true${scope.sql}${workflowFilter(query,'j','job')} order by j.created_at desc limit $${scope.params.length+1}`,[...scope.params,limit]);return{ok:true,records:r.rows,statuses:['scheduled','in_progress','paused','waiting_parts','waiting_customer','blocked','completed','closed','canceled']};}
