  if(match?.action==='assign'&&method==='POST'){requireManage(user,'jobs');await db.query(`update jobs set assigned_user_id=$2::uuid,status=case when status in ('completed','closed') then status else 'scheduled' end,updated_at=now() where id=$1`,[match.id,maybeUuid(body.assignedUserId)||maybeUuid(body.userId)]);return{ok:true,id:match.id};}
  if(match?.action==='status'&&method==='POST'){requireManage(user,'jobs');await db.query(`update jobs set status=$2,updated_at=now() where id=$1`,[match.id,str(body.status,'scheduled')]);return{ok:true,id:match.id,status:str(body.status,'scheduled')};}
  const statusActions:Record<string,string>={'start':'in_progress','pause':'paused','waiting-parts':'waiting_parts','waiting-customer':'waiting_customer','complete':'completed'};
  if(match?.action&&statusActions[match.action]&&method==='POST'){requireManage(user,'jobs');const extra=match.action==='start'?`,started_at=coalesce(started_at,now())`:match.action==='complete'?`,completed_at=now()`:'';await db.query(`update jobs set status=$2,updated_at=now()${extra} where id=$1`,[match.id,statusActions[match.action]]);return{ok:true,id:match.id,status:statusActions[match.action]};}
  if(match?.action==='closeout'&&method==='POST') return handleWorkflowRoute(`/jobs/${match.id}/closeout`,'POST',{...body,createInvoice: body.createInvoice ?? true},user,query,db);
  if(match?.action==='create-invoice'&&method==='POST'){requireManage(user,'invoices');const j=await db.query<any>(`select j.client_id::text as "clientId",j.quote_id::text as "quoteId",j.request_id::text as "requestId",j.property_id::text as "propertyId",q.client_id::text as "quoteClientId",wr.client_id::text as "requestClientId",p.client_id::text as "propertyClientId" from jobs j left join quotes q on q.id=j.quote_id left join work_requests wr on wr.id=j.request_id left join properties p on p.id=j.property_id where j.id=$1`,[match.id]); if(!j.rows[0]) throw new HttpError(404,'Job not found'); const clientId=j.rows[0].clientId||j.rows[0].quoteClientId||j.rows[0].requestClientId||j.rows[0].propertyClientId||(user.role==='Client'?user.clientId:null); if(!clientId) throw new HttpError(400,'INVOICE_CLIENT_REQUIRED:Cannot create invoice because no client is linked to this job.'); await db.query(`update jobs set client_id=$2,updated_at=now() where id=$1 and client_id is null`,[match.id,clientId]); const inv=await db.query(`insert into invoices (client_id,job_id,quote_id,request_id,property_id,status,total_cents,balance_cents) values ($1,$2,$3,$4,$5,'draft',0,0) returning id::text`,[clientId,match.id,j.rows[0].quoteId,j.rows[0].requestId,j.rows[0].propertyId]);return{ok:true,id:inv.rows[0].id,clientId};}
  if(match&&method==='GET'){const r=await db.query<any>(`select j.id::text,j.client_id::text as "clientId",j.assigned_user_id::text as "assignedUserId",j.property_id::text as "propertyId",j.quote_id::text as "quoteId",j.request_id::text as "requestId",j.title,j.status,j.scope,j.completed_at::text as "completedAt",c.display_name as client,p.address as property,u.name as technician from jobs j left join clients c on c.id=j.client_id left join properties p on p.id=j.property_id left join users u on u.id=j.assigned_user_id where j.id=$1`,[match.id]);if(!r.rows[0])throw new HttpError(404,'Job not found');await assertAccess(user,{clientId:r.rows[0].clientId,assignedUserId:r.rows[0].assignedUserId});const [notes,orders,media,invoices,timeline]=await Promise.all([db.query(`select id::text,note,customer_visible as "customerVisible",created_at::text as "createdAt" from technician_notes where job_id=$1 order by created_at desc`,[match.id]),db.query(`select id::text,status,scope,assigned_user_id::text as "assignedUserId" from work_orders where job_id=$1`,[match.id]),linkedMedia(db,'job',match.id),db.query(`select id::text,status,balance_cents as balance,total_cents as total from invoices where job_id=$1`,[match.id]),db.query(`select id::text,title as summary,created_at::text as "createdAt" from activity_events where entity_type='job' and entity_id=$1 order by created_at desc limit 50`,[match.id]).catch(()=>({rows:[]} as any))]);return{ok:true,record:{...r.rows[0],notes:notes.rows,workOrders:orders.rows,attachments:media,invoices:invoices.rows,timeline:timeline.rows}};}
  if(match?.action&&['archive','restore','delete'].includes(match.action)&&method==='POST') return softAction(db, 'jobs', match.id, match.action, user);
